using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

// --- Tools ---
var notes = new NoteStore();
var webSearch = new WebSearchService();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) => webSearch.SearchAsync(query),
        "web_search",
        "Search the web for information on a topic. Returns a list of result snippets."),

    AIFunctionFactory.Create(
        ([Description("The text content to save as a note")] string content,
         [Description("A short label for the note")] string label) =>
        {
            notes.Add(label, content);
            return $"Note saved: \"{label}\"";
        },
        "save_note",
        "Save a piece of information as a labeled note for later reference."),

    AIFunctionFactory.Create(
        () => notes.GetAll(),
        "get_notes",
        "Retrieve all notes saved so far."),
};

// --- Agent setup ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient();

var systemPrompt = """
    You are a research agent. Your job is to research a topic the user provides.

    Workflow:
    1. Break the topic into 2-3 search queries.
    2. Use the web_search tool to find information for each query.
    3. Use the save_note tool to record key findings from each search.
    4. After researching, use get_notes to review everything you collected.
    5. Provide a well-structured summary with key findings and sources.

    Be thorough but concise. Always cite sources when possible.
    """;

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- Main loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or       ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research this topic: {topic}"),
    };

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"Researching \"{topic}\"...\n");
    Console.ResetColor();

    // Agent loop — keep going while the model wants to call tools
    while (true)
    {
        var response = await chatClient.GetResponseAsync(messages, chatOptions);
        messages.AddMessages(response);

        // Process any tool calls in the response
        var toolCalls = response.Messages
            .SelectMany(m => m.Contents)
            .OfType<FunctionCallContent>()
            .ToList();

        if (toolCalls.Count == 0)
        {
            // No more tool calls — print the final answer
            var answer = response.Messages
                .SelectMany(m => m.Contents)
                .OfType<TextContent>()
                .LastOrDefault()?.Text;

            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine("── Research Summary ─────────────────────");
            Console.ResetColor();
            Console.WriteLine(answer ?? "(no response)");
            Console.WriteLine();
            break;
        }

        // Execute each tool call
        foreach (var call in toolCalls)
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"  🔧 {call.Name}({FormatArgs(call.Arguments)})");
            Console.ResetColor();

            var tool = tools.FirstOrDefault(t => t.Name == call.Name);
            object? result = tool is not null
                ? await tool.InvokeAsync(call.Arguments)
                : $"Unknown tool: {call.Name}";

            var resultContent = result?.ToString() ?? "(no result)";
            messages.Add(new ChatMessage(ChatRole.Tool,
            [
                new FunctionResultContent(call.CallId, resultContent),
            ]));
        }
    }
}

Console.WriteLine("Goodbye!");
return;

static string FormatArgs(IReadOnlyDictionary<string, object?>? args) =>
    args is null ? "" : string.Join(", ", args.Select(kv => $"{kv.Key}: \"{kv.Value}\""));

// ─── Supporting types ───────────────────────────────────────────

/// <summary>Simple in-memory note store used by the agent.</summary>
sealed class NoteStore
{
    private readonly List<(string Label, string Content)> _notes = [];

    public void Add(string label, string content) => _notes.Add((label, content));
    public void Clear() => _notes.Clear();

    public string GetAll() => _notes.Count == 0
        ? "(no notes saved yet)"
        : string.Join("\n\n", _notes.Select((n, i) => $"[{i + 1}] {n.Label}\n{n.Content}"));
}

/// <summary>Lightweight web search via DuckDuckGo Lite (no API key required).</summary>
sealed class WebSearchService : IDisposable
{
    private readonly HttpClient _http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    public async Task<string> SearchAsync(string query)
    {
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await _http.GetStringAsync(url);
            return ParseResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string ParseResults(string html)
    {
        var sb = new StringBuilder();
        var resultCount = 0;

        // Extract result snippets from DuckDuckGo Lite HTML
        var snippetTag = "class=\"result__snippet\"";
        var titleTag = "class=\"result__a\"";
        var urlTag = "class=\"result__url\"";
        var idx = 0;

        while (resultCount < 5 && (idx = html.IndexOf(titleTag, idx, StringComparison.Ordinal)) >= 0)
        {
            resultCount++;
            var title = ExtractTagContent(html, idx);
            var snippetPos = html.IndexOf(snippetTag, idx, StringComparison.Ordinal);
            var snippet = snippetPos >= 0 ? ExtractTagContent(html, snippetPos) : "";
            var urlPos = html.IndexOf(urlTag, idx, StringComparison.Ordinal);
            var resultUrl = urlPos >= 0 ? ExtractTagContent(html, urlPos).Trim() : "";

            sb.AppendLine($"### {title.Trim()}");
            if (!string.IsNullOrWhiteSpace(resultUrl))
                sb.AppendLine($"URL: {resultUrl}");
            if (!string.IsNullOrWhiteSpace(snippet))
                sb.AppendLine(snippet.Trim());
            sb.AppendLine();

            idx += titleTag.Length;
        }

        return resultCount == 0 ? "No results found." : sb.ToString();
    }

    private static string ExtractTagContent(string html, int attrPos)
    {
        var closeAngle = html.IndexOf('>', attrPos);
        if (closeAngle < 0) return "";
        var start = closeAngle + 1;
        var end = html.IndexOf('<', start);
        if (end < 0) return "";
        return System.Net.WebUtility.HtmlDecode(html[start..end]);
    }

    public void Dispose() => _http.Dispose();
}

