/// <summary>Simple in-memory note store used by the agent.</summary>
sealed class NoteStore
{
    private readonly List<(string Label, string Content)> _notes = [];

    public void Add(string label, string content) => _notes.Add((label, content));
    public void Clear() => _notes.Clear();

    public string GetAll() => _notes.Count == 0
        ? "(no notes saved yet)"
        : string.Join("\n\n", _notes.Select((n, i) => $"[{i + 1}] {n.Label}\n{n.Content}"));
}

/// <summary>Lightweight web search via DuckDuckGo Lite (no API key required).</summary>
sealed class WebSearchService : IDisposable
{
    private readonly HttpClient _http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    public async Task<string> SearchAsync(string query)
    {
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await _http.GetStringAsync(url);
            return ParseResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string ParseResults(string html)
    {
        var sb = new StringBuilder();
        var resultCount = 0;

        // Extract result snippets from DuckDuckGo Lite HTML
        var snippetTag = "class=\"result__snippet\"";
        var titleTag = "class=\"result__a\"";
        var urlTag = "class=\"result__url\"";
        var idx = 0;

        while (resultCount < 5 && (idx = html.IndexOf(titleTag, idx, StringComparison.Ordinal)) >= 0)
        {
            resultCount++;
            var title = ExtractTagContent(html, idx);
            var snippetPos = html.IndexOf(snippetTag, idx, StringComparison.Ordinal);
            var snippet = snippetPos >= 0 ? ExtractTagContent(html, snippetPos) : "";
            var urlPos = html.IndexOf(urlTag, idx, StringComparison.Ordinal);
            var resultUrl = urlPos >= 0 ? ExtractTagContent(html, urlPos).Trim() : "";

            sb.AppendLine($"### {title.Trim()}");
            if (!string.IsNullOrWhiteSpace(resultUrl))
                sb.AppendLine($"URL: {resultUrl}");
            if (!string.IsNullOrWhiteSpace(snippet))
                sb.AppendLine(snippet.Trim());
            sb.AppendLine();

            idx += titleTag.Length;
        }

        return resultCount == 0 ? "No results found." : sb.ToString();
    }

    private static string ExtractTagContent(string html, int attrPos)
    {
        var closeAngle = html.IndexOf('>', attrPos);
        if (closeAngle < 0) return "";
        var start = closeAngle + 1;
        var end = html.IndexOf('<', start);
        if (end < 0) return "";
        return System.Net.WebUtility.HtmlDecode(html[start..end]);
    }

    public void Dispose() => _http.Dispose();
}

