152. /// <summary>Simple in-memory note store used by the agent.</summary>
153. sealed class NoteStore
154. {
155.     private readonly List<(string Label, string Content)> _notes = [];
156. 
157.     public void Add(string label, string content) => _notes.Add((label, content));
158.     public void Clear() => _notes.Clear();
159. 
160.     public string GetAll() => _notes.Count == 0
161.         ? "(no notes saved yet)"
162.         : string.Join("\n\n", _notes.Select((n, i) => $"[{i + 1}] {n.Label}\n{n.Content}"));
163. }
