165. /// <summary>Lightweight web search via DuckDuckGo Lite (no API key required).</summary>
166. sealed class WebSearchService : IDisposable
167. {
168.     private readonly HttpClient _http = new()
169.     {
170.         DefaultRequestHeaders =
171.         {
172.             { "User-Agent", "ResearchAgent/1.0" },
173.         },
174.     };
175. 
176.     public async Task<string> SearchAsync(string query)
177.     {
178.         try
179.         {
180.             var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
181.             var html = await _http.GetStringAsync(url);
182.             return ParseResults(html);
183.         }
184.         catch (Exception ex)
185.         {
186.             return $"Search failed: {ex.Message}";
187.         }
188.     }
189. 
190.     private static string ParseResults(string html)
191.     {
192.         var sb = new StringBuilder();
193.         var resultCount = 0;
194. 
195.         // Extract result snippets from DuckDuckGo Lite HTML
196.         var snippetTag = "class=\"result__snippet\"";
197.         var titleTag = "class=\"result__a\"";
198.         var urlTag = "class=\"result__url\"";
199.         var idx = 0;
200. 
201.         while (resultCount < 5 && (idx = html.IndexOf(titleTag, idx, StringComparison.Ordinal)) >= 0)
202.         {
203.             resultCount++;
204.             var title = ExtractTagContent(html, idx);
205.             var snippetPos = html.IndexOf(snippetTag, idx, StringComparison.Ordinal);
206.             var snippet = snippetPos >= 0 ? ExtractTagContent(html, snippetPos) : "";
207.             var urlPos = html.IndexOf(urlTag, idx, StringComparison.Ordinal);
208.             var resultUrl = urlPos >= 0 ? ExtractTagContent(html, urlPos).Trim() : "";
209. 
210.             sb.AppendLine($"### {title.Trim()}");
211.             if (!string.IsNullOrWhiteSpace(resultUrl))
212.                 sb.AppendLine($"URL: {resultUrl}");
213.             if (!string.IsNullOrWhiteSpace(snippet))
214.                 sb.AppendLine(snippet.Trim());
215.             sb.AppendLine();
216. 
217.             idx += titleTag.Length;
218.         }
219. 
220.         return resultCount == 0 ? "No results found." : sb.ToString();
221.     }
222. 
223.     private static string ExtractTagContent(string html, int attrPos)
224.     {
225.         var closeAngle = html.IndexOf('>', attrPos);
226.         if (closeAngle < 0) return "";
227.         var start = closeAngle + 1;
228.         var end = html.IndexOf('<', start);
229.         if (end < 0) return "";
230.         return System.Net.WebUtility.HtmlDecode(html[start..end]);
231.     }
232. 
233.     public void Dispose() => _http.Dispose();
234. }
