             if (!string.IsNullOrWhiteSpace(resultUrl))
                 sb.AppendLine($"URL: {resultUrl}");
             if (!string.IsNullOrWhiteSpace(snippet))
                 sb.AppendLine(snippet.Trim());
             sb.AppendLine();

             idx += titleTag.Length;
         }

         return resultCount == 0 ? "No results found." : sb.ToString();
     }

     private static string ExtractTagContent(string html, int attrPos)
     {
         var closeAngle = html.IndexOf('>', attrPos);
         if (closeAngle < 0) return "";
         var start = closeAngle + 1;
         var end = html.IndexOf('<', start);
         if (end < 0) return "";
         return System.Net.WebUtility.HtmlDecode(html[start..end]);
     }

     public void Dispose() => _http.Dispose();
